package com.google.gson.internal;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.NonNullElementWrapperList;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.util.ArrayList;

class NonNullElementWrapperListTest {

  NonNullElementWrapperList<String> list;
  ArrayList<String> delegateMock;

  @BeforeEach
  void setUp() throws Exception {
    delegateMock = mock(ArrayList.class);
    // Use reflection to create NonNullElementWrapperList with mocked delegate
    list = new NonNullElementWrapperList<>(new ArrayList<>());
    Field delegateField = NonNullElementWrapperList.class.getDeclaredField("delegate");
    delegateField.setAccessible(true);
    delegateField.set(list, delegateMock);
  }

  @Test
  void equals_withSameDelegateObject_returnsTrue() {
    when(delegateMock.equals(delegateMock)).thenReturn(true);

    assertTrue(list.equals(delegateMock));
    verify(delegateMock).equals(delegateMock);
  }

  @Test
  void equals_withDifferentObject_returnsDelegateEqualsResult() {
    Object other = new Object();
    when(delegateMock.equals(other)).thenReturn(false);

    boolean result = list.equals(other);

    assertFalse(result);
    verify(delegateMock).equals(other);
  }

  @Test
  void equals_withNullObject_returnsDelegateEqualsResult() {
    when(delegateMock.equals(null)).thenReturn(false);

    boolean result = list.equals(null);

    assertFalse(result);
    verify(delegateMock).equals(null);
  }

  @Test
  void equals_withSameNonNullElementWrapperList_returnsDelegateEqualsResult() {
    NonNullElementWrapperList<String> otherList = new NonNullElementWrapperList<>(new ArrayList<>());
    Field delegateField = null;
    try {
      delegateField = NonNullElementWrapperList.class.getDeclaredField("delegate");
      delegateField.setAccessible(true);
      delegateField.set(otherList, delegateMock);
    } catch (Exception e) {
      fail("Reflection failed");
    }

    when(delegateMock.equals(otherList)).thenReturn(true);

    boolean result = list.equals(otherList);

    assertTrue(result);
    verify(delegateMock).equals(otherList);
  }
}
